+    /// POST /v1/completions - Legacy text completion (OpenAI format)
+    fn handleOpenAICompletions(self: *Self, stream: std.net.Stream, method: []const u8, body: []const u8) !void {
+        if (!std.mem.eql(u8, method, "POST")) {
+            try self.sendOpenAIError(stream, 405, "invalid_request_error", "Method not allowed");
+            stream.close();
+            return;
+        }
+
+        // Parse OpenAI completions request
+        const parsed = std.json.parseFromSlice(OpenAICompletionsRequest, self.allocator, body, .{
+            .ignore_unknown_fields = true,
+        }) catch {
+            try self.sendOpenAIError(stream, 400, "invalid_request_error", "Invalid JSON");
+            stream.close();
+            return;
+        };
+        defer parsed.deinit();
+
+        const comp_req = parsed.value;
+        const stream_mode = comp_req.stream orelse false;
+        const max_tokens = comp_req.max_tokens orelse 256;
+
+        // Build prompt directly (no chat format for legacy completions)
+        const prompt_owned = try self.allocator.dupe(u8, comp_req.prompt);
+
+        // Check queue capacity
+        self.queue_mutex.lock();
+        const queue_len = self.request_queue.items.len;
+        const max_queue = self.config.max_concurrent * 2;
+        self.queue_mutex.unlock();
+
+        if (queue_len >= max_queue) {
+            self.allocator.free(prompt_owned);
+            try self.sendOpenAIError(stream, 503, "server_error", "Server busy - queue full");
+            stream.close();
+            return;
+        }
+
+        const request_id = self.next_request_id.fetchAdd(1, .monotonic);
+
+        self.queue_mutex.lock();
+        self.request_queue.append(self.allocator, .{
+            .id = request_id,
+            .stream = stream,
+            .cell_id = null,
+            .prompt = prompt_owned,
+            .system_prompt_len = 0,
+            .max_tokens = max_tokens,
+            .submitted_at = std.time.milliTimestamp(),
+            .api_format = .openai_completions,
+            .stream_mode = stream_mode,
+            .bytes_sent = 0,
+            .sse_started = false,
+            .stop_sequences = null,
+            .hit_stop_sequence = null,
+        }) catch {
+            self.queue_mutex.unlock();
+            self.allocator.free(prompt_owned);
+            try self.sendOpenAIError(stream, 500, "server_error", "Failed to queue request");
+            stream.close();
+            return;
+        };
+        self.queue_mutex.unlock();
+
+        logger.info("Queued OpenAI completions request {}: max_tokens={}", .{ request_id, max_tokens });
+    }
+
