+    // ================== OpenAI Streaming Support ==================
+
+    /// Send OpenAI SSE streaming chunk for chat completions
+    fn sendOpenAIChatStreamChunk(self: *Self, stream: std.net.Stream, text: []const u8, req_id: u64) !void {
+        // Escape text for JSON
+        var escaped: std.ArrayListUnmanaged(u8) = .{};
+        defer escaped.deinit(self.allocator);
+
+        for (text) |ch| {
+            switch (ch) {
+                '"' => try escaped.appendSlice(self.allocator, "\\\""),
+                '\\' => try escaped.appendSlice(self.allocator, "\\\\"),
+                '\n' => try escaped.appendSlice(self.allocator, "\\n"),
+                '\r' => try escaped.appendSlice(self.allocator, "\\r"),
+                '\t' => try escaped.appendSlice(self.allocator, "\\t"),
+                else => {
+                    if (ch < 0x20) {
+                        var buf: [6]u8 = undefined;
+                        const len = std.fmt.bufPrint(&buf, "\\u{x:0>4}", .{ch}) catch continue;
+                        try escaped.appendSlice(self.allocator, len);
+                    } else {
+                        try escaped.append(self.allocator, ch);
+                    }
+                },
+            }
+        }
+
+        const timestamp = std.time.timestamp();
+        var buffer: [4096]u8 = undefined;
+        const json = std.fmt.bufPrint(&buffer,
+            \\{{"id":"chatcmpl-{d}","object":"chat.completion.chunk","created":{d},"model":"{s}","choices":[{{"index":0,"delta":{{"content":"{s}"}},"finish_reason":null}}]}}
+        , .{ req_id, timestamp, self.model_name, escaped.items }) catch return;
+
+        _ = try stream.write("data: ");
+        _ = try stream.write(json);
+        _ = try stream.write("\n\n");
+    }
+
