+    /// Handle OpenAI streaming completion
+    fn handleOpenAIStreamingCompletion(self: *Self, req: *PendingRequest, cell: *Cell) void {
+        // Send any remaining text
+        if (cell.buffer.items.len > req.bytes_sent) {
+            const new_text = cell.buffer.items[req.bytes_sent..];
+            switch (req.api_format) {
+                .openai => self.sendOpenAIChatStreamChunk(req.stream, new_text, req.id) catch {},
+                .openai_completions => self.sendOpenAICompletionsStreamChunk(req.stream, new_text, req.id) catch {},
+                else => {},
+            }
+        }
+
+        // Send final chunk with finish_reason
+        const timestamp = std.time.timestamp();
+        var buffer: [512]u8 = undefined;
+
+        const final_json = switch (req.api_format) {
+            .openai => std.fmt.bufPrint(&buffer,
+                \\{{"id":"chatcmpl-{d}","object":"chat.completion.chunk","created":{d},"model":"{s}","choices":[{{"index":0,"delta":{{}},"finish_reason":"stop"}}]}}
+            , .{ req.id, timestamp, self.model_name }) catch return,
+            .openai_completions => std.fmt.bufPrint(&buffer,
+                \\{{"id":"cmpl-{d}","object":"text_completion","created":{d},"model":"{s}","choices":[{{"text":"","index":0,"finish_reason":"stop"}}]}}
+            , .{ req.id, timestamp, self.model_name }) catch return,
+            else => return,
+        };
+
+        _ = req.stream.write("data: ") catch {};
+        _ = req.stream.write(final_json) catch {};
+        _ = req.stream.write("\n\ndata: [DONE]\n\n") catch {};
+    }
